import React from 'react';
import Amenities from './Amenities.js';
import HouseRules from './HouseRules.js';
import HealthAndSafety from './HealthAndSafety.js';
import CancellationPolicy from './CancellationPolicy.js';
import {Link, useLocation} from "react-router-dom";
import Footer from './Footer.js';
import Header from './Header.js';
import 'bootstrap/dist/css/bootstrap.min.css';
import { useState, useEffect } from 'react';
import Reviews from './Reviews.js';
import ConfirmReservation from './ConfirmReservation.js';

//Not being used for now
function ShowFavourites(){
    return(
        <>
            <span>Add to favoutites </span>
            <button value="favourites" className="placeicon"><i className="fa-thin fa-heart" style={{color : 'black'}}></i></button>
        </>
    );
}



export default function Temp({property}) {
    let location = useLocation();
    console.log(location);
    console.log(location.state.reviews);

    /**
     * Code for Add to/Remove from favourites
     */
     const [showFavourite, setShowFavourite] = useState(false);
     const onClick = (showFavourite) => setShowFavourite(!showFavourite)


    const [checkin, setCheckin] = useState("");
    const [checkout, setCheckout] = useState("");

    const onChangeHandler = event => {
        setCheckin(event.target.value);
     };

     const onChangeHandler2 = event => {
        setCheckout(event.target.value);
     };



    console.log(checkin);
    console.log(checkout);


  return (
    // <>
    //   <span className="card-text">{location.state.description}</span><br />
    //   <span className="card-text"><b><u>Guests:</u> {location.state.beds}</b></span><br />
    //   <span className="card-text"><b><u>Bedrooms:</u> {location.state.bedrooms}</b></span><br />
    //   <span className="card-text"><b><u>Beds:</u> {location.state.beds}</b></span><br />
    //   <span className="card-text"><b><u>Guests:</u> {location.state.beds}</b></span><br />
    //   <span className="card-text"><b><u>Baths:</u> {location.state.baths}</b></span><br />
    //   <span className="card-text"><b><u>Cleaning Fees:</u> ${location.state.cleaningFee}</b></span><br />
    //   <span className="card-text"><b><u>Service Fees:</u> ${location.state.serviceFee}</b></span><br />
    //   <span className="card-text"><b><u>Ameneties:</u></b> {location.state.amenities}</span><br />
    //   <span className="card-text"><b><u>Stars:</u></b> {location.state.reviews.stars}</span><br />
    //   <span className="card-text"><b><u>Total Reviews:</u></b> {location.state.reviews.totalReviews}</span><br />
    // </>

    <>
        <Header />

        <div style={{margin: '6%', }}>
            {/*Title of property*/}
            <div style={{display : 'flex'}}>
                <div style={{flex : '1'}}>
                    <h3>{location.state.title}</h3>
                </div>

                <div style={{flex : '1', textAlign : 'right'}} onClick={()=>setShowFavourite(!showFavourite)}>
                    {showFavourite ? <>
                                        <span>Add to favoutites </span>
                                        <button value="favourites" className="placeicon"><i className="fa-thin fa-heart" style={{color : 'black'}}></i></button>
                                    </> 
                    : null}

                    {!showFavourite ? <><span>Remove from favoutites </span>
                                        <button value="favourites" className="placeicon"> <i className="fa-light fa-heart" style={{color : 'red'}}></i></button></> 
                    : null}

                </div>
            </div>
            {/*reviews and location*/}
            <div>
                <span><i className="fa-sharp fa-solid fa-star placeicon" />&nbsp; {location.state.reviews.stars}</span>
                <span>.</span>
                <span><a href="#morereviews" className="nodecoration" data-bs-toggle="modal" data-bs-target="#morereviews"><u>{location.state.reviews.totalReviews} reviews</u></a></span>
                <span>.</span>
                <span><a href="#" className="nodecoration"><u>{location.state.location}</u></a></span>
                <span />
            </div>

            <br />

            <hr style={{marginRight: '10%'}} />
            {/*Images*/}
            <div className="flex-container">
                <span className="card">
                <a href="#moreimages" data-bs-toggle="modal" data-bs-target="#moreimages"><img className="card-img-top" src="../img/property1img1.jpg" alt="Card image cap" /></a>
                </span>
                <span className="card">
                <a href="#moreimages" data-bs-toggle="modal" data-bs-target="#moreimages"><img className="card-img-top" src="../img/property2img1.jpg" alt="Card image cap" /></a>
                </span>
                <span className="card">
                <a href="#moreimages" data-bs-toggle="modal" data-bs-target="#moreimages"><img className="card-img-top" src="../img/property3img1.jpg" alt="Card image cap" /></a>
                </span>
                {/* <span className="card">
                <a href="#moreimages" data-bs-toggle="modal" data-bs-target="#moreimages"><img className="card-img-top" src="../img/property4img1.jpg" alt="Card image cap" /></a>
                </span> */}
                {/* Modal */}
                <div className="modal fade" id="moreimages" data-bs-backdrop="static" data-bs-keyboard="false" tabIndex={-1} aria-labelledby="moreimageslabel" aria-hidden="true">
                    <div className="modal-dialog">
                        <div className="modal-content">
                        <div className="modal-header">
                            <h3 className="modal-title fs-5" id="moreimageslabel">More Images</h3>
                            <button type="button" className="btn-close fa-thin fa-xmark placeicon" data-bs-dismiss="modal" aria-label="Close" />
                        </div>
                        <div className="modal-body">
                            <div>
                            <span><img className="card-img-top" src="../img/property1img1.jpg" alt="Card image cap" /></span>
                            <span><img className="card-img-top" src="../img/property1img1.jpg" alt="Card image cap" /></span>
                            <span><img className="card-img-top" src="../img/property1img1.jpg" alt="Card image cap" /></span>
                            <span><img className="card-img-top" src="../img/property1img1.jpg" alt="Card image cap" /></span>
                            <span><img className="card-img-top" src="../img/property1img1.jpg" alt="Card image cap" /></span>
                            <span><img className="card-img-top" src="../img/property1img1.jpg" alt="Card image cap" /></span>
                            <span><img className="card-img-top" src="../img/property1img1.jpg" alt="Card image cap" /></span>
                            <span><img className="card-img-top" src="../img/property1img1.jpg" alt="Card image cap" /></span>
                            </div>
                        </div>
                        </div>
                    </div>
                </div>
                <modal1 />
            </div>

            <hr style={{marginRight: '10%'}} />

            <div style={{display: 'flex'}}> {/*flex => side by side divs*/}
                {/*left div*/}
                <div style={{flex: 1}}>
                {/*hosted by*/}
                <div>
                    <span><p>{location.state.hostMessage}</p></span>
                </div>
                {/*Max size*/}
                <div>
                    <span>{location.state.guests} guests </span>
                    <span>{location.state.beds} bed </span>
                    <span>{location.state.baths} bath</span>
                </div>

                {/*Description of property*/}
                <div>
                    {location.state.description}
                </div>
                <hr style={{marginRight: '10%'}} />

                {/*Amenities*/}
                <div>
                    <div><h5>Amenities</h5></div>
                    <div className style={{height: '10%'}}>
                        <Amenities allAmenities={location.state.amenities} limit={true}/>
                    </div>
                    <div className="overflow-scroll" style={{textAlign: 'left'}}>
                    {/* Button trigger modal */}
                    <span><a href="#moreamanities" className="nodecoration" data-bs-toggle="modal" data-bs-target="#moreamanities"><u>See more...</u></a></span>
                    {/* Modal */}
                    <div className="modal fade" id="moreamanities" data-bs-backdrop="static" data-bs-keyboard="false" tabIndex={-1} aria-labelledby="moreamanitieslabel" aria-hidden="true">
                        <div className="modal-dialog">
                            <div className="modal-content">
                                <div className="modal-header">
                                <h3 className="modal-title fs-5" id="moreamanitieslabel">More Amenities</h3>
                                <button type="button" className="btn-close fa-thin fa-xmark placeicon" data-bs-dismiss="modal" aria-label="Close" />
                                </div>
                                <div className="modal-body">
                                    <div>
                                        <Amenities allAmenities={location.state.amenities} limit={false}/>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                    </div>
                </div>

                <hr style={{marginRight: '10%'}} />

                </div>
                {/*right div*/}
                <div className="card" style={{flex: 1, textAlign : 'center'}}>

                    <form method="post" action="/temp/confirmreservation" >

                        <div style={{paddingBottom: '18px'}}>
                            CheckIn : <input placeholder="Check In" type="date" name="checkin" id="checkin" value={checkin} onChange={onChangeHandler} style={{maxWidth : '250px'}}  />
                        </div>

                        <div style={{paddingBottom: '18px'}}>
                            CheckOut : <input placeholder="Check Out" type="date" name="checkout" id="checkout" value={checkout} onChange={onChangeHandler2} style={{maxWidth : '250px'}} />
                        </div>

                        <div style={{paddingBottom: '18px'}}>
                            Guests : <input min={1} max={location.state.guests} type="number" name="guests" id="guests" name="guestss" style={{maxWidth : '250px'}} />
                        </div>

                        {/* <Link to={{pathname : '/temp/confirmreservation', state : location.state, checkin : checkin, checkout : checkout}}> */}
                        <Link to={`/temp/confirmreservation/${location.state},${checkin},${checkout}`}>
                            <div className="reserve"><input name="skip_Submit" defaultValue="Submit" type="submit"  />
                            </div>
                        </Link>

                        <div>
                            for per night : {location.state.nightlyFee}
                        </div>

                        <div>
                            <span>Cleaning fee : {location.state.cleaningFee}</span>
                        </div>

                        <div>
                            <span>Service fee : {location.state.serviceFee}</span>
                        </div>

                        <hr />

                        <div>
                            Total before taxes : {location.state.nightlyFee + location.state.cleaningFee + location.state.serviceFee}
                        </div>

                    </form>
                </div>
            </div> 

            {/*Additional Policies*/}
            <div style={{display: 'flex'}}>
                {/*House Rules*/}
                <div style={{flex: 1}}>
                <div><h5>House Rules</h5></div>
                    <span style={{flex: 1}}>
                        <HouseRules allHouseRules={location.state.houseRules}/>
                    </span>
                </div>

                {/*Health and saftey*/}
                <div style={{flex: 1}}>
                <div><h5>Health and saftey</h5></div>
                    <span style={{flex: 1}}>
                        <HealthAndSafety allHealthAndSafety={location.state.healthAndSafety} />
                    </span>
                </div>
                {/*Cancelation Policy*/}
                <div style={{flex: 1}}>
                <div><h5>Cancelation Policy</h5></div>
                    <span style={{flex: 1}}>
                        {/* <CancellationPolicy allcancellationPolicy={location.state.cancellationPolicy} /> */}
                        {location.state.cancellationPolicy}
                    </span>
                </div>
            </div>
            <hr style={{marginRight: '10%'}} />

            {/*Reviews*/}
            <Reviews reviewJson={location.state.reviews} />

        </div>

        <Footer />

    </>

    // <>
    //     <div>TEMP</div>
    // </>
  )
}
